import React from 'react';
import {
  LinErpListFilterBar,
  SearchInput,
  type AccountSearchRecord,
  type SearchInputConfig,
} from '@linm-soft-org/linm-web-common-components';
import { formatAccountDisplay } from '../../../components/search/accountSearchApi';
import erp from '../../../styles/erpPage.module.css';
import styles from '../SoCaiPage/SoCaiReportFilterBar.module.css';

export type CashLedgerReportFilterBarLabels = {
  fieldAccount?: string;
  fieldDateRange: string;
  expandDateRangeAriaLabel: string;
  view: string;
  accountPlaceholder?: string;
};

export type CashLedgerReportFilterBarProps = {
  testIdPrefix: string;
  labels: CashLedgerReportFilterBarLabels;
  showOptionalAccountFilter: boolean;
  accountSearchConfig?: SearchInputConfig<AccountSearchRecord>;
  accountCode?: string;
  accountName?: string;
  onAccountChange?: (code: string, name: string) => void;
  onAccountClear?: () => void;
  fromDate?: string;
  toDate?: string;
  onDateChange: (fromDate?: string, toDate?: string) => void;
  onView: () => void;
  loading?: boolean;
};

export const CashLedgerReportFilterBar: React.FC<CashLedgerReportFilterBarProps> = ({
  testIdPrefix,
  labels,
  showOptionalAccountFilter,
  accountSearchConfig,
  accountCode = '',
  accountName = '',
  onAccountChange,
  onAccountClear,
  fromDate,
  toDate,
  onDateChange,
  onView,
  loading = false,
}) => (
  <LinErpListFilterBar
    testIdPrefix={testIdPrefix}
    fromDate={fromDate}
    toDate={toDate}
    onDateChange={onDateChange}
    dateLabel={labels.fieldDateRange}
    expandDateRangeAriaLabel={labels.expandDateRangeAriaLabel}
    onSearch={onView}
    searchAriaLabel={labels.view}
    loading={loading}
    leading={
      showOptionalAccountFilter && accountSearchConfig && onAccountChange && onAccountClear ? (
        <div
          className={styles.filterFieldAccount}
          data-testid={`${testIdPrefix}-field-account`}
        >
          <div className={`${styles.filterFieldAccountInner} ${erp.searchInGrid}`}>
            <SearchInput
              config={accountSearchConfig}
              label={labels.fieldAccount ?? 'Tài khoản'}
              value={accountCode}
              primaryDisplay={
                accountCode
                  ? formatAccountDisplay(accountCode, accountName)
                  : labels.accountPlaceholder
              }
              onChange={a => onAccountChange(a.code, a.name)}
              onClear={onAccountClear}
              showSecondaryInput={false}
              placeholder={labels.accountPlaceholder}
            />
          </div>
        </div>
      ) : undefined
    }
  />
);

export default CashLedgerReportFilterBar;
